#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node *left, *right;
    Node(int v): val(v), left(nullptr), right(nullptr) {}
};

bool isBST(Node* root, long long minVal, long long maxVal) {
    if (!root) return true;
    if (root->val <= minVal || root->val >= maxVal) return false;
    return isBST(root->left, minVal, root->val) && isBST(root->right, root->val, maxVal);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; 
    if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for (int i = 0; i < N-1; ++i) {
            int pi, ci; char dir; 
            cin >> pi >> ci >> dir;
            if (!mp.count(pi)) mp[pi] = new Node(pi);
            if (!mp.count(ci)) mp[ci] = new Node(ci);
            if (dir == 'L') mp[pi]->left = mp[ci];
            else mp[pi]->right = mp[ci];
            childSet.insert(ci);
        }
        Node* root = nullptr;
        for (auto &p : mp) {
            if (!childSet.count(p.first)) { root = p.second; break; }
        }
        cout << (isBST(root, LLONG_MIN, LLONG_MAX) ? "YES" : "NO") << '\n';
        // free memory
        for (auto &p : mp) delete p.second;
    }
    return 0;
}

