import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static boolean isBST(Node node, long min, long max) {
        if (node == null) return true;
        if (node.val <= min || node.val >= max) return false;
        return isBST(node.left, min, node.val) && isBST(node.right, node.val, max);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> child = new HashSet<>();
            for (int i = 0; i < N-1; ++i) {
                st = new StringTokenizer(br.readLine());
                int pi = Integer.parseInt(st.nextToken());
                int ci = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(pi, new Node(pi));
                map.putIfAbsent(ci, new Node(ci));
                Node parent = map.get(pi);
                Node childNode = map.get(ci);
                if (dir == 'L') parent.left = childNode; else parent.right = childNode;
                child.add(ci);
            }
            Node root = null;
            for (int val : map.keySet()) {
                if (!child.contains(val)) { root = map.get(val); break; }
            }
            out.append(isBST(root, Long.MIN_VALUE, Long.MAX_VALUE) ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

