import sys
sys.setrecursionlimit(1_000_000)

def is_bst(node, lo, hi):
    if node is None:
        return True
    if not (lo < node.val < hi):
        return False
    return is_bst(node.left, lo, node.val) and is_bst(node.right, node.val, hi)

class Node:
    __slots__ = ('val', 'left', 'right')
    def __init__(self, v):
        self.val = v
        self.left = None
        self.right = None

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = {}
        child_set = set()
        for __ in range(N-1):
            pi = int(next(it)); ci = int(next(it)); dirc = next(it)
            if pi not in nodes:
                nodes[pi] = Node(pi)
            if ci not in nodes:
                nodes[ci] = Node(ci)
            if dirc == 'L':
                nodes[pi].left = nodes[ci]
            else:
                nodes[pi].right = nodes[ci]
            child_set.add(ci)
        root = None
        for val in nodes:
            if val not in child_set:
                root = nodes[val]
                break
        out_lines.append('YES' if is_bst(root, -float('inf'), float('inf')) else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

